function uuidv4() {
  if (globalThis.crypto && typeof crypto.randomUUID === 'function') return crypto.randomUUID();
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function (c) {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

// Explicit status tokens decide first; message sniffing is a last resort with word
// boundaries, and DOWN patterns are checked BEFORE up ('upstream connect error',
// 'backup failed' must never classify a real outage as resolved).
function statusFrom(raw, msg) {
  const s = String(raw == null ? '' : raw).trim().toLowerCase();
  if (s === '0' || s === 'down' || s === 'open') return 'open';
  if (s === '1' || s === 'up' || s === 'resolved') return 'resolved';
  const m = String(msg || '').toLowerCase();
  if (/\b(down|fail|failed|failing|failure|offline|timeout|timed out|unreachable|error)\b/.test(m)) return 'open';
  if (/\b(up|online|recovered|recovery|resolved|restored|ok)\b/.test(m)) return 'resolved';
  return 'open';
}

// Uptime Kuma tags arrive as objects ({tag/name, value/color}), not strings.
// String(t) on an object is '[object Object]', which made the old /^region:/ test
// always fail -> region null -> the tenant query dropped its region filter and
// counted ALL active tenants as impacted. Handle both shapes; fail to null.
function regionFrom(tags) {
  if (!Array.isArray(tags)) return null;
  for (const t of tags) {
    if (t != null && typeof t === 'object') {
      const k = String(t.tag || t.name || t.key || '');
      const v = t.value != null ? String(t.value) : '';
      if (/^region$/i.test(k) && v) return v.trim();
      const packed = /^region:(.+)$/i.exec(v);
      if (packed) return packed[1].trim();
    } else {
      const m = /^region:(.+)$/i.exec(String(t));
      if (m) return m[1].trim();
    }
  }
  return null;
}

const root = $input.first().json || {};
let body = root.body || root;
// Replay payloads may carry the full webhook envelope ({headers,query,body}); unwrap it.
if (body && typeof body === 'object' && body.body && typeof body.body === 'object' && (body.headers || body.query || body.webhookUrl)) body = body.body;
// Uptime Kuma puts status/time/msg on heartbeat and the name on monitor; keep both in reach.
const heartbeat = (body.heartbeat && typeof body.heartbeat === 'object') ? body.heartbeat : {};
const monitor = (body.monitor && typeof body.monitor === 'object') ? body.monitor : ((body.data && typeof body.data === 'object') ? body.data : heartbeat);
const replay = !!root.replay;
const response_required = !!root.body && !replay;

// Shared-secret gate for the public webhook path. Replay entries are in-process and
// trusted. Unset secret = open gate (dev degrade, same spirit as the TELEGRAM_* fallbacks).
const secret = $env.FLOWOPS_WEBHOOK_SECRET || '';
const reqHeaders = (root.headers && typeof root.headers === 'object') ? root.headers : {};
const authorized = !response_required || !secret || String(reqHeaders['x-flowops-secret'] || '') === secret;

const supabase_url = ($env.SUPABASE_URL || '').replace(/\/$/, '');
const monitor_id = String(body.monitor_id || monitor.id || monitor.monitorID || heartbeat.monitorID || body.id || 'unknown');
const monitor_name = body.monitor_name || monitor.name || monitor.hostname || body.name || 'Unknown monitor';
// ?? not ||: Uptime Kuma sends heartbeat.status = 0 for DOWN, and 0 is falsy.
const statusRaw = body.incident_status ?? body.status ?? heartbeat.status ?? monitor.status;
const message = body.msg || body.message || heartbeat.msg || monitor.msg || null;
const incident_status = statusFrom(statusRaw, message);
const sevRaw = String(body.severity || '').toLowerCase();
const severity = ['minor', 'major', 'critical'].includes(sevRaw) ? sevRaw : (incident_status === 'open' ? 'major' : 'minor');
const region = body.region || monitor.region || regionFrom(body.tags) || regionFrom(monitor.tags) || null;

// tenant_id feeds FK columns (idempotency_keys, audit_log) and a bad value would 4xx
// AFTER the 202 was already sent, killing the run as poison. Incidents are
// tenant-agnostic, so anything that is not a UUID of an existing tenant degrades to null.
const UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
const rawTenant = body.tenant_id || root.tenant_id || null;
let tenant_id = (typeof rawTenant === 'string' && UUID_RE.test(rawTenant)) ? rawTenant.toLowerCase() : null;
if (tenant_id && supabase_url) {
  try {
    const found = await this.helpers.httpRequest({ method: 'GET', url: supabase_url + '/rest/v1/tenants?id=eq.' + tenant_id + '&select=id&limit=1', headers: { apikey: $env.SUPABASE_SERVICE_KEY, Authorization: 'Bearer ' + $env.SUPABASE_SERVICE_KEY, accept: 'application/json' }, json: true, timeout: 10000 });
    if (!Array.isArray(found) || found.length === 0) tenant_id = null;
  } catch (e) {
    tenant_id = null;
  }
}

// Per-event id. body.id is deliberately NOT used as an event id (it is usually the
// monitor id; a DOWN and its UP would collide and the resolve would be deduped away).
// The derived fallback keys on status + the event's own timestamp; last resort is a
// minute bucket - never 'latest' - so a monitor's NEXT outage can never be swallowed
// as a duplicate of its first one.
const event_time = body.time || body.created_at || heartbeat.time || heartbeat.localDateTime || new Date().toISOString().slice(0, 16);
const stable_id = body.event_id || body.heartbeat_id || heartbeat.id || monitor.heartbeatID;
const event_id = String(stable_id || (monitor_id + ':' + incident_status + ':' + event_time));
const idem_key = 'incident:' + event_id;
const correlation_id = replay && root.correlation_id ? root.correlation_id : uuidv4();

return [{ json: {
  tenant_id,
  monitor_id,
  monitor_name,
  incident_status,
  severity,
  region,
  message,
  event_id,
  idem_key,
  replay,
  response_required,
  authorized,
  correlation_id,
  execution_id: String($execution.id),
  supabase_url
} }];

const p = $('Normalize Incident').first().json;
// Fetch Impacted Tenants runs with fullResponse:true -> single wrapper item {body,statusCode,...}
// even when PostgREST returns []. A non-array body means the lookup itself FAILED
// (onError:continueRegularOutput) -> impact is UNKNOWN, not zero; flag it instead of
// publishing a fabricated 0 in the incident row and the Telegram comms.
const resp = $('Fetch Impacted Tenants').first().json || {};
const ok = Array.isArray(resp.body);
const tenants = ok ? resp.body.filter(t => t && t.id) : [];
// Aggregates only: incidents is anon-readable (status-page style), so per-tenant
// name/plan/region (PII) must NOT be embedded in the row. Counts by plan/region
// preserve impact analytics without leaking tenant identity.
const countBy = (arr, key) => {
  const m = {};
  for (const t of arr) { const v = (t && t[key] != null) ? String(t[key]) : 'unknown'; m[v] = (m[v] || 0) + 1; }
  return m;
};
const byPlan = countBy(tenants, 'plan');
const byRegion = countBy(tenants, 'region');
return [{ json: { tenant_id: p.tenant_id, correlation_id: p.correlation_id, monitor_id: p.monitor_id, monitor_name: p.monitor_name, severity: p.severity, status: p.incident_status === 'resolved' ? 'resolved' : 'open', region: p.region, impact_count: tenants.length, impact_unknown: !ok, impact_by_plan: byPlan, impact_by_region: byRegion, postmortem: { message: p.message, source: p.replay ? 'replay' : 'uptime-kuma', event_id: p.event_id, impact_unknown: !ok, impact_by_plan: byPlan, impact_by_region: byRegion } } }];

// Was a blind POST. Now:
//  - a resolved event CLOSES the matching open/monitoring row(s) for this monitor
//    (PATCH) instead of inserting a second row and leaving the first open forever;
//    if nothing was open, a resolved row is still inserted for the record;
//  - a replay checks correlation_id first, so re-running an execution that already
//    wrote its incident does not duplicate the row (replay bypasses the idempotency
//    gate by design and incidents has no natural unique key).
// Errors here throw -> G1 error handler -> DLQ, same as the old HTTP node.
const p = $('Normalize Incident').first().json;
const row = $input.first().json;
const base = p.supabase_url + '/rest/v1/incidents';
const H = { apikey: $env.SUPABASE_SERVICE_KEY, Authorization: 'Bearer ' + $env.SUPABASE_SERVICE_KEY, 'Content-Type': 'application/json', Prefer: 'return=representation' };
const req = (opts) => this.helpers.httpRequest(Object.assign({ json: true, timeout: 15000, headers: H }, opts));

let action = null;
let incident = null;

if (row.status === 'resolved') {
  const closed = await req({ method: 'PATCH', url: base + '?monitor_id=eq.' + encodeURIComponent(row.monitor_id) + '&status=in.(open,monitoring)', body: { status: 'resolved' } });
  if (Array.isArray(closed) && closed.length > 0) { action = 'closed'; incident = closed[0]; }
}

if (!incident && p.replay) {
  const existing = await req({ method: 'GET', url: base + '?correlation_id=eq.' + encodeURIComponent(row.correlation_id) + '&select=id,status&limit=1' });
  if (Array.isArray(existing) && existing.length > 0) { action = 'replay-already-written'; incident = existing[0]; }
}

if (!incident) {
  const inserted = await req({ method: 'POST', url: base, body: {
    correlation_id: row.correlation_id,
    monitor_id: row.monitor_id,
    monitor_name: row.monitor_name,
    severity: row.severity,
    status: row.status,
    region: row.region,
    impact_count: row.impact_count,
    postmortem: row.postmortem
  } });
  incident = Array.isArray(inserted) ? inserted[0] : inserted;
  action = 'inserted';
}

return [{ json: { action, incident_id: incident && incident.id ? incident.id : null, status: row.status, correlation_id: row.correlation_id } }];

const p = $('Normalize Incident').first().json;
const row = $('Prep Incident Row').first().json;
const text = [
  p.incident_status === 'resolved' ? 'Incident resolved' : 'Incident opened',
  'Monitor: ' + p.monitor_name + ' (' + p.monitor_id + ')',
  'Severity: ' + p.severity + (p.region ? ' | Region: ' + p.region : ''),
  'Impacted active tenants: ' + (row.impact_unknown ? 'unknown (tenant lookup failed)' : row.impact_count),
  'Correlation: ' + p.correlation_id
].join('\n');
let alert_delivered = false;
let notice = null;
const token = $env.TELEGRAM_BOT_TOKEN;
const chat = $env.TELEGRAM_CHAT_ID;
if (token && chat) {
  try {
    // Plain text on purpose: parse_mode:'Markdown' makes Telegram 400 on unbalanced
    // '_' / '*' in monitor names, silently killing the alert this service exists to send.
    await this.helpers.httpRequest({ method: 'POST', url: 'https://api.telegram.org/bot' + token + '/sendMessage', body: { chat_id: chat, text }, json: true, timeout: 15000 });
    alert_delivered = true;
  } catch (e) {
    // Never persist the raw error: n8n error messages can embed the request URL,
    // which contains the bot token. audit_log is anon-readable in dev.
    notice = 'telegram failed: ' + String(e && e.message ? e.message : e).split(token).join('[token]');
  }
} else {
  notice = 'telegram skipped: TELEGRAM_BOT_TOKEN / TELEGRAM_CHAT_ID not set';
}
return [{ json: { tenant_id: p.tenant_id, correlation_id: p.correlation_id, alert_delivered, notice, impact_count: row.impact_count, impact_unknown: !!row.impact_unknown } }];

const p = $('Normalize Incident').first().json;
const n = $('Notify Telegram').first().json;
const u = $('Upsert Incident').first().json;
return [{ json: { tenant_id: p.tenant_id, correlation_id: p.correlation_id, service: 'incident', step: 'segment-tenants', status: 'success', payload: { monitor_id: p.monitor_id, status: p.incident_status, region: p.region, impact_count: n.impact_count, impact_unknown: n.impact_unknown, incident_action: u.action, incident_id: u.incident_id, telegram_delivered: n.alert_delivered, notice: n.notice } } }];
